import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import {
  CurrencyDollarIcon,
  LockClosedIcon,
  ArrowTrendingUpIcon,
  DocumentTextIcon,
  CheckCircleIcon,
  ClockIcon,
  ExclamationTriangleIcon
} from '@heroicons/react/24/outline';
import { prnovaService, PRNWallet, PRNCertificate } from '../../services/prnovaService';

interface PRNWalletCardProps {
  className?: string;
}

const PRNWalletCard: React.FC<PRNWalletCardProps> = ({ className = '' }) => {
  const [wallet, setWallet] = useState<PRNWallet | null>(null);
  const [certificates, setCertificates] = useState<PRNCertificate[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadPRNData();
  }, []);

  const loadPRNData = async () => {
    try {
      setLoading(true);
      const [walletData, certsData] = await Promise.all([
        prnovaService.getWalletBalance(),
        prnovaService.getUserCertificates()
      ]);

      setWallet(walletData);
      setCertificates(certsData);
    } catch (err: any) {
      setError('Failed to load PRN data');
      console.error('PRN data error:', err);
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'pledged':
        return (
          <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900/20 dark:text-blue-400">
            <LockClosedIcon className="w-3 h-3 mr-1" />
            Pledged
          </span>
        );
      case 'active':
        return (
          <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800 dark:bg-green-900/20 dark:text-green-400">
            <CheckCircleIcon className="w-3 h-3 mr-1" />
            Active
          </span>
        );
      case 'released':
        return (
          <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-800 dark:bg-gray-900/20 dark:text-gray-400">
            <CheckCircleIcon className="w-3 h-3 mr-1" />
            Released
          </span>
        );
      default:
        return (
          <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800 dark:bg-yellow-900/20 dark:text-yellow-400">
            <ClockIcon className="w-3 h-3 mr-1" />
            Pending
          </span>
        );
    }
  };

  if (loading) {
    return (
      <div className={`bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6 ${className}`}>
        <div className="animate-pulse">
          <div className="h-6 bg-gray-200 dark:bg-gray-700 rounded w-1/3 mb-4"></div>
          <div className="space-y-3">
            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded"></div>
            <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-2/3"></div>
          </div>
        </div>
      </div>
    );
  }

  if (error || !wallet) {
    return (
      <div className={`bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-6 ${className}`}>
        <div className="text-center py-4">
          <ExclamationTriangleIcon className="mx-auto h-8 w-8 text-red-400 mb-2" />
          <p className="text-sm text-red-600 dark:text-red-400">
            {error || 'Failed to load PRN wallet'}
          </p>
        </div>
      </div>
    );
  }

  const activeCertificates = certificates.filter(cert => cert.status === 'pledged');
  const totalPRNValue = activeCertificates.reduce((sum, cert) => sum + parseFloat(cert.usd_value.toString()), 0);

  return (
    <div className={`bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-gray-800 dark:to-gray-700 rounded-xl shadow-sm border border-blue-200 dark:border-gray-600 p-6 ${className}`}>
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center">
          <div className="p-3 bg-blue-600 rounded-lg">
            <CurrencyDollarIcon className="h-6 w-6 text-white" />
          </div>
          <div className="ml-4">
            <h3 className="text-xl font-bold text-gray-900 dark:text-white">
              PRN Wallet
            </h3>
            <p className="text-sm text-gray-600 dark:text-gray-400">
              Pronova (PRN) • 1:1 USD Peg
            </p>
          </div>
        </div>
        <Link
          to="/pronova"
          className="text-blue-600 hover:text-blue-700 dark:text-blue-400 dark:hover:text-blue-300 text-sm font-medium"
        >
          View Details →
        </Link>
      </div>

      {/* Wallet Balance Grid */}
      <div className="grid grid-cols-2 gap-4 mb-6">
        <div className="bg-white dark:bg-gray-800 rounded-lg p-4 border border-gray-200 dark:border-gray-600">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wide">
                Total Balance
              </p>
              <p className="text-2xl font-bold text-gray-900 dark:text-white">
                {parseFloat(wallet.balance.toString()).toFixed(2)}
              </p>
              <p className="text-sm text-gray-600 dark:text-gray-400">
                PRN
              </p>
            </div>
            <div className="text-right">
              <p className="text-lg font-semibold text-green-600 dark:text-green-400">
                ${parseFloat(wallet.balance.toString()).toFixed(2)}
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                USD
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 rounded-lg p-4 border border-gray-200 dark:border-gray-600">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wide">
                Pledged
              </p>
              <p className="text-2xl font-bold text-gray-900 dark:text-white">
                {parseFloat(wallet.pledged_balance.toString()).toFixed(2)}
              </p>
              <p className="text-sm text-gray-600 dark:text-gray-400">
                PRN
              </p>
            </div>
            <div className="text-right">
              <p className="text-lg font-semibold text-orange-600 dark:text-orange-400">
                ${parseFloat(wallet.pledged_balance.toString()).toFixed(2)}
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                USD
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Active Certificates */}
      {activeCertificates.length > 0 && (
        <div className="bg-white dark:bg-gray-800 rounded-lg p-4 border border-gray-200 dark:border-gray-600 mb-4">
          <div className="flex items-center justify-between mb-3">
            <h4 className="text-sm font-semibold text-gray-900 dark:text-white">
              Active Certificates ({activeCertificates.length})
            </h4>
            <Link
              to="/documents"
              className="text-blue-600 hover:text-blue-700 dark:text-blue-400 text-xs font-medium"
            >
              View All
            </Link>
          </div>

          <div className="space-y-2">
            {activeCertificates.slice(0, 2).map((cert) => (
              <div
                key={cert.id}
                className="flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-700 rounded-lg"
              >
                <div className="flex items-center">
                  <DocumentTextIcon className="h-4 w-4 text-blue-500 mr-2" />
                  <div>
                    <p className="text-sm font-medium text-gray-900 dark:text-white">
                      {cert.certificate_number}
                    </p>
                    <div className="flex items-center space-x-2">
                      {getStatusBadge(cert.status)}
                      {cert.capimax_investment_active && (
                        <span className="inline-flex items-center px-2 py-1 rounded-full text-xs font-medium bg-purple-100 text-purple-800 dark:bg-purple-900/20 dark:text-purple-400">
                          <ArrowTrendingUpIcon className="w-3 h-3 mr-1" />
                          Capimax Active
                        </span>
                      )}
                    </div>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-sm font-semibold text-gray-900 dark:text-white">
                    {parseFloat(cert.prn_amount.toString()).toFixed(2)} PRN
                  </p>
                  <p className="text-xs text-gray-500 dark:text-gray-400">
                    ${parseFloat(cert.usd_value.toString()).toFixed(2)}
                  </p>
                </div>
              </div>
            ))}

            {activeCertificates.length > 2 && (
              <div className="text-center py-2">
                <p className="text-xs text-gray-500 dark:text-gray-400">
                  +{activeCertificates.length - 2} more certificates
                </p>
              </div>
            )}
          </div>
        </div>
      )}

      {/* PRN Info Banner */}
      <div className="bg-blue-600 rounded-lg p-4 text-white">
        <div className="flex items-center justify-between">
          <div>
            <h4 className="font-semibold text-sm">Understanding PRN</h4>
            <p className="text-xs text-blue-100 mt-1">
              PRN tokens are pegged 1:1 with USD and backed by Nova Finance reserves
            </p>
          </div>
          <div className="text-right">
            <p className="text-xl font-bold">1 PRN</p>
            <p className="text-xs text-blue-100">= $1.00 USD</p>
          </div>
        </div>
      </div>

      {/* No PRN State */}
      {certificates.length === 0 && (
        <div className="text-center py-6">
          <CurrencyDollarIcon className="mx-auto h-12 w-12 text-gray-400 mb-3" />
          <h4 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
            No PRN Tokens Yet
          </h4>
          <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
            Apply for a loan to receive PRN tokens and electronic certificates
          </p>
          <Link
            to="/apply-loan"
            className="inline-flex items-center px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 transition-colors"
          >
            Apply for Loan
          </Link>
        </div>
      )}
    </div>
  );
};

export default PRNWalletCard;
